import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum View {
  HOME = 'home',
  WEALTH = 'wealth',
  GLOBAL = 'global',
  PROFILE = 'profile',
  CONVERT = 'convert'
}

export interface Transaction {
  id: string;
  name: string;
  date: string;
  amount: number;
  currency: 'USD' | 'EUR' | 'GBP' | 'NGN';
  type: 'expense' | 'income';
  icon: string;
}

export interface Wallet {
  currency: string;
  label: string;
  balance: number;
  symbol: string;
  flagUrl: string;
  color: string;
}

import React, { useState } from 'react';
import { View } from './types';
import Home from './components/Home';
import Convert from './components/Convert';
import Navigation from './components/Navigation';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.HOME);

  const renderContent = () => {
    switch (currentView) {
      case View.HOME:
        return <Home onNavigateToConvert={() => setCurrentView(View.CONVERT)} />;
      case View.CONVERT:
        return <Convert onBack={() => setCurrentView(View.HOME)} />;
      case View.WEALTH:
      case View.GLOBAL:
      case View.PROFILE:
        return (
          <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center">
             <span className="material-icons-round text-6xl text-slate-300 mb-4">construction</span>
             <h2 className="text-xl font-bold mb-2 uppercase tracking-widest">{currentView} View</h2>
             <p className="text-slate-500">This section is currently under development.</p>
             <button 
                onClick={() => setCurrentView(View.HOME)}
                className="mt-6 px-6 py-2 bg-primary text-background-dark font-bold rounded-xl"
             >
                Back Home
             </button>
          </div>
        );
      default:
        return <Home onNavigateToConvert={() => setCurrentView(View.CONVERT)} />;
    }
  };

  return (
    <div className="flex justify-center min-h-screen w-full relative overflow-hidden transition-colors duration-500">
      <div className="absolute inset-0 pattern-overlay pointer-events-none"></div>

      <div className="w-full max-w-md flex flex-col relative z-10 bg-background-light dark:bg-background-dark min-h-screen">
        {/* Dynamic Content */}
        <div className="flex-1">
          {renderContent()}
        </div>

        {/* Global Navigation - Only show on main dashboard views */}
        {currentView !== View.CONVERT && (
          <Navigation currentView={currentView} onNavigate={setCurrentView} />
        )}
      </div>

      {/* Theme Toggle - Fixed Floating for accessibility */}
      <button 
        className="fixed bottom-24 right-4 md:right-auto md:left-[calc(50%+200px)] bg-white dark:bg-surface-dark p-3 rounded-full shadow-lg border border-slate-200 dark:border-white/10 z-[60] active:scale-95 transition-all"
        onClick={() => document.documentElement.classList.toggle('dark')}
      >
        <span className="material-icons-round dark:text-white block">
          {typeof document !== 'undefined' && document.documentElement.classList.contains('dark') ? 'light_mode' : 'dark_mode'}
        </span>
      </button>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';

interface ConvertProps {
  onBack: () => void;
}

const EXCHANGE_RATE = 1605.00;

const Convert: React.FC<ConvertProps> = ({ onBack }) => {
  const [inputValue, setInputValue] = useState('450,000');
  const [numericValue, setNumericValue] = useState(450000);

  const handleKeyPress = (key: string) => {
    let current = inputValue.replace(/,/g, '');
    if (key === 'backspace') {
      current = current.slice(0, -1);
    } else if (key === '.') {
      if (!current.includes('.')) current += '.';
    } else {
      if (current === '0') current = key;
      else current += key;
    }

    if (current === '') current = '0';

    // Validate number
    const num = parseFloat(current);
    if (!isNaN(num)) {
      setNumericValue(num);
      // Format with commas
      const parts = current.split('.');
      parts[0] = parseInt(parts[0]).toLocaleString();
      setInputValue(parts.join('.'));
    } else if (current === '0' || current === '') {
      setNumericValue(0);
      setInputValue('0');
    }
  };

  const calculatedValue = (numericValue / EXCHANGE_RATE).toFixed(2);

  return (
    <div className="flex flex-col min-h-screen bg-background-light dark:bg-background-dark relative">
      <div className="absolute inset-0 pattern-overlay pointer-events-none"></div>

      {/* Header */}
      <header className="px-6 py-4 flex items-center justify-between z-10">
        <button 
          onClick={onBack}
          className="w-10 h-10 flex items-center justify-center rounded-full bg-slate-200/50 dark:bg-white/10 active:scale-90 transition-all"
        >
          <span className="material-icons-round text-lg">arrow_back_ios_new</span>
        </button>
        <h1 className="text-lg font-bold tracking-tight">Convert Currency</h1>
        <div className="w-10"></div> 
      </header>

      {/* Input Areas */}
      <main className="flex-1 px-6 pt-2 z-10 flex flex-col">
        {/* You Send */}
        <div className="bg-white/50 dark:bg-surface-dark border border-slate-200 dark:border-white/5 p-5 rounded-[32px] mb-3 backdrop-blur-sm transition-all">
          <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em]">You Send</span>
            <span className="text-[10px] text-slate-400 dark:text-slate-500 font-medium">Balance: ₦1,240,000.00</span>
          </div>
          <div className="flex justify-between items-end">
            <div className="flex items-center gap-2 bg-slate-100 dark:bg-white/5 p-2 pr-4 rounded-[20px] cursor-pointer active:scale-95 transition-transform">
              <div className="w-8 h-8 rounded-full bg-green-600 flex items-center justify-center text-white text-[9px] font-black">NGN</div>
              <span className="font-bold text-sm">NGN</span>
              <span className="material-icons-round text-slate-400 text-sm">expand_more</span>
            </div>
            <div className="text-3xl font-bold tracking-tighter">
              {inputValue}<span className="text-primary animate-pulse">|</span>
            </div>
          </div>
        </div>

        {/* Swap Button */}
        <div className="flex justify-center -my-6 relative z-20">
          <div className="bg-primary text-background-dark w-12 h-12 rounded-[18px] flex items-center justify-center shadow-lg border-4 border-background-light dark:border-background-dark active:rotate-180 transition-all duration-300">
            <span className="material-icons-round font-bold">swap_vert</span>
          </div>
        </div>

        {/* They Receive */}
        <div className="bg-white/50 dark:bg-surface-dark border border-slate-200 dark:border-white/5 p-5 rounded-[32px] pt-8 backdrop-blur-sm">
          <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em]">They Receive</span>
            <span className="text-[10px] text-primary font-bold uppercase tracking-wider">Rate: 1 USD = ₦1,605.00</span>
          </div>
          <div className="flex justify-between items-end">
            <div className="flex items-center gap-2 bg-slate-100 dark:bg-white/5 p-2 pr-4 rounded-[20px] cursor-pointer active:scale-95 transition-transform">
              <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center text-white text-[9px] font-black">USD</div>
              <span className="font-bold text-sm">USD</span>
              <span className="material-icons-round text-slate-400 text-sm">expand_more</span>
            </div>
            <div className="text-3xl font-bold tracking-tighter text-slate-400 dark:text-slate-500">
              {calculatedValue}
            </div>
          </div>
        </div>

        {/* Savings Badge */}
        <div className="mt-6 p-4 rounded-[24px] bg-secondary-dark/40 border border-accent-purple/20 flex items-center gap-4 animate-in slide-in-from-bottom-2 duration-500">
          <div className="w-12 h-12 rounded-2xl bg-accent-purple/20 flex items-center justify-center text-accent-purple shadow-inner">
            <span className="material-icons-round">trending_up</span>
          </div>
          <div className="flex-1">
            <p className="text-[9px] text-slate-400 uppercase font-black tracking-[0.2em]">Savings vs Banks</p>
            <p className="text-sm font-medium leading-tight">You save <span className="text-primary font-bold">₦24,500</span> compared to traditional banks.</p>
          </div>
        </div>
      </main>

      {/* Numeric Keypad */}
      <div className="px-6 pb-6 pt-4 z-10">
        <div className="grid grid-cols-3 gap-y-2 gap-x-4 mb-6">
          {['1', '2', '3', '4', '5', '6', '7', '8', '9', '.', '0', 'backspace'].map((key) => (
            <button 
              key={key}
              onClick={() => handleKeyPress(key)}
              className="h-14 text-2xl font-bold flex items-center justify-center rounded-2xl hover:bg-slate-200/50 dark:hover:bg-white/5 active:bg-primary/20 active:scale-95 transition-all text-slate-900 dark:text-white"
            >
              {key === 'backspace' ? (
                <span className="material-icons-round">backspace</span>
              ) : key}
            </button>
          ))}
        </div>
        <button 
          className="w-full bg-primary hover:brightness-105 active:scale-[0.98] transition-all text-background-dark font-black py-5 rounded-[24px] text-lg shadow-xl shadow-primary/20 uppercase tracking-widest"
        >
          Confirm Conversion
        </button>
        <div className="mt-8 flex justify-center">
          <div className="w-32 h-1.5 bg-slate-300 dark:bg-white/20 rounded-full"></div>
        </div>
      </div>
    </div>
  );
};

export default Convert;

