import React, { useState, useEffect, useCallback } from 'react';
import { GoogleGenAI } from "@google/genai";

interface ConvertProps {
  onBack: () => void;
}

const Convert: React.FC<ConvertProps> = ({ onBack }) => {
  const [inputValue, setInputValue] = useState('450,000');
  const [numericValue, setNumericValue] = useState(450000);
  const [exchangeRate, setExchangeRate] = useState(1605.00);
  const [isLoadingRate, setIsLoadingRate] = useState(false);
  const [lastUpdated, setLastUpdated] = useState<string>('');

  const ZERAH_FEE_PERCENT = 0.001; // 0.1%

  // Fetch live rate using Gemini Google Search Grounding for accuracy
  const fetchLiveRate = useCallback(async () => {
    setIsLoadingRate(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview",
        contents: "What is the current mid-market exchange rate for 1 USD to NGN (Nigerian Naira) right now? Return only the number.",
        config: {
          tools: [{ googleSearch: {} }],
        },
      });

      const text = response.text || "";
      const matches = text.match(/(\d+[,.]\d+)|(\d+)/g);
      if (matches && matches.length > 0) {
        const rate = parseFloat(matches[0].replace(',', ''));
        if (!isNaN(rate) && rate > 1000) {
          setExchangeRate(rate);
          setLastUpdated(new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit', second: '2-digit' }));
        }
      }
    } catch (error) {
      console.error("Failed to fetch live rate:", error);
      // Fallback to a slightly varied default if API fails
      setExchangeRate(prev => prev + (Math.random() - 0.5) * 2);
    } finally {
      setIsLoadingRate(false);
    }
  }, []);

  useEffect(() => {
    fetchLiveRate();
    const interval = setInterval(fetchLiveRate, 60000); // Refresh every minute
    return () => clearInterval(interval);
  }, [fetchLiveRate]);

  const handleKeyPress = (key: string) => {
    let current = inputValue.replace(/,/g, '');
    if (key === 'backspace') {
      current = current.slice(0, -1);
    } else if (key === '.') {
      if (!current.includes('.')) current += '.';
    } else {
      if (current === '0') current = key;
      else current += key;
    }

    if (current === '') current = '0';

    const num = parseFloat(current);
    if (!isNaN(num)) {
      setNumericValue(num);
      const parts = current.split('.');
      parts[0] = parseInt(parts[0]).toLocaleString();
      setInputValue(parts.join('.'));
    } else if (current === '0' || current === '') {
      setNumericValue(0);
      setInputValue('0');
    }
  };

  // Calculations
  const zerahFee = numericValue * ZERAH_FEE_PERCENT;
  const netAmount = numericValue - zerahFee;
  const calculatedValue = (netAmount / exchangeRate).toFixed(2);

  return (
    <div className="flex flex-col min-h-screen bg-background-light dark:bg-background-dark relative">
      <div className="absolute inset-0 pattern-overlay pointer-events-none"></div>

      {/* Header */}
      <header className="px-6 py-4 flex items-center justify-between z-10">
        <button 
          onClick={onBack}
          className="w-10 h-10 flex items-center justify-center rounded-full bg-slate-200/50 dark:bg-white/10 active:scale-90 transition-all"
        >
          <span className="material-icons-round text-lg">arrow_back_ios_new</span>
        </button>
        <div className="text-center">
            <h1 className="text-lg font-bold tracking-tight">Convert Currency</h1>
            <div className="flex items-center justify-center gap-1.5 mt-0.5">
                <span className={`w-1.5 h-1.5 rounded-full ${isLoadingRate ? 'bg-amber-500 animate-ping' : 'bg-green-500'}`}></span>
                <span className="text-[9px] font-black uppercase tracking-[0.1em] text-slate-400">
                    Live Market • {lastUpdated || 'Updating...'}
                </span>
            </div>
        </div>
        <button 
            onClick={fetchLiveRate}
            className={`w-10 h-10 flex items-center justify-center rounded-full bg-slate-200/50 dark:bg-white/10 active:rotate-180 transition-all duration-500 ${isLoadingRate ? 'animate-spin' : ''}`}
        >
          <span className="material-icons-round text-lg">refresh</span>
        </button>
      </header>

      {/* Input Areas */}
      <main className="flex-1 px-6 pt-2 z-10 flex flex-col">
        {/* You Send */}
        <div className="bg-white/50 dark:bg-surface-dark border border-slate-200 dark:border-white/5 p-5 rounded-[32px] mb-3 backdrop-blur-sm transition-all group focus-within:ring-2 ring-primary/20">
          <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em]">You Send</span>
            <span className="text-[10px] text-slate-400 dark:text-slate-500 font-medium italic">Balance: ₦1,240,000.00</span>
          </div>
          <div className="flex justify-between items-end">
            <div className="flex items-center gap-2 bg-slate-100 dark:bg-white/5 p-2 pr-4 rounded-[20px] cursor-pointer active:scale-95 transition-transform border border-transparent hover:border-slate-200 dark:hover:border-white/10">
              <div className="w-8 h-8 rounded-full bg-green-600 flex items-center justify-center text-white text-[9px] font-black shadow-inner">NGN</div>
              <span className="font-bold text-sm">NGN</span>
              <span className="material-icons-round text-slate-400 text-sm">expand_more</span>
            </div>
            <div className="text-4xl font-bold tracking-tighter overflow-hidden">
              {inputValue}<span className="text-primary animate-pulse">|</span>
            </div>
          </div>
        </div>

        {/* Swap Button Area */}
        <div className="flex justify-center -my-6 relative z-20">
          <div className="bg-primary text-background-dark w-12 h-12 rounded-[20px] flex items-center justify-center shadow-xl border-4 border-background-light dark:border-background-dark active:rotate-180 transition-all duration-300 cursor-pointer group">
            <span className="material-icons-round font-bold group-hover:scale-110 transition-transform">swap_vert</span>
          </div>
        </div>

        {/* They Receive */}
        <div className="bg-white/50 dark:bg-surface-dark border border-slate-200 dark:border-white/5 p-5 rounded-[32px] pt-8 backdrop-blur-sm shadow-sm">
          <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em]">They Receive</span>
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-primary/10 border border-primary/20">
                <span className="text-[9px] text-primary font-bold uppercase tracking-wider">Rate: 1 USD = ₦{exchangeRate.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
            </div>
          </div>
          <div className="flex justify-between items-end">
