            <span className="text-[10px] text-slate-400 dark:text-slate-500 font-medium italic">Balance: {fromCurrency.symbol}1,240,000.00</span>
          </div>
          <div className="flex justify-between items-end">
            <div 
              onClick={() => setShowSelector('from')}
              className="flex items-center gap-2 bg-slate-100 dark:bg-white/5 p-2 pr-4 rounded-[20px] cursor-pointer active:scale-95 transition-transform border border-transparent hover:border-slate-200 dark:hover:border-white/10"
            >
              <div className="w-8 h-8 rounded-full overflow-hidden flex items-center justify-center border border-white/10 shadow-inner">
                <img src={fromCurrency.flagUrl} alt={fromCurrency.code} className="w-full h-full object-cover" />
              </div>
              <span className="font-bold text-sm">{fromCurrency.code}</span>
              <span className="material-icons-round text-slate-400 text-sm">expand_more</span>
            </div>
            <div className="text-4xl font-bold tracking-tighter overflow-hidden">
              {inputValue}<span className="text-primary animate-pulse">|</span>
            </div>
          </div>
        </div>

        {/* Swap Button Area */}
