          <div className="flex justify-between items-center mb-2">
            <span className="text-[10px] font-bold text-slate-500 dark:text-slate-400 uppercase tracking-[0.2em]">They Receive</span>
            <div className="flex items-center gap-1.5 px-2 py-0.5 rounded-full bg-primary/10 border border-primary/20">
                <span className="text-[9px] text-primary font-bold uppercase tracking-wider">
                  Rate: 1 {fromCurrency.code} = {exchangeRate.toLocaleString(undefined, { maximumFractionDigits: 6 })} {toCurrency.code}
                </span>
            </div>
          </div>
          <div className="flex justify-between items-end">
