              onClick={() => setShowSelector('to')}
              className="flex items-center gap-2 bg-slate-100 dark:bg-white/5 p-2 pr-4 rounded-[20px] cursor-pointer active:scale-95 transition-transform border border-transparent hover:border-slate-200 dark:hover:border-white/10"
            >
              <div className="w-8 h-8 rounded-full overflow-hidden flex items-center justify-center border border-white/10 shadow-inner">
