              </div>
              <span className="font-bold text-sm">{toCurrency.code}</span>
              <span className="material-icons-round text-slate-400 text-sm">expand_more</span>
            </div>
            <div className="text-4xl font-bold tracking-tighter text-slate-400 dark:text-slate-500/50">
              {calculatedValue}
            </div>
          </div>
        </div>

        {/* Transaction Breakdown */}
        <div className="mt-6 space-y-3">
            <div className="p-5 rounded-[28px] bg-white/30 dark:bg-white/5 border border-slate-200 dark:border-white/5 backdrop-blur-md">
                <h4 className="text-[10px] font-black uppercase tracking-[0.2em] text-slate-400 mb-3 px-1">Transaction Details</h4>
                <div className="space-y-2">
                    <div className="flex justify-between items-center text-xs">
                        <span className="text-slate-500 dark:text-slate-400">Subtotal</span>
                        <span className="font-bold">{fromCurrency.symbol}{numericValue.toLocaleString(undefined, { minimumFractionDigits: 2 })}</span>
                    </div>
                    <div className="flex justify-between items-center text-xs">
                        <div className="flex items-center gap-1.5">
                            <span className="text-slate-500 dark:text-slate-400">Zerah Fee</span>
