                </div>
                <div>
                  <p className="font-bold text-sm">{tx.name}</p>
                  <p className="text-[10px] font-medium text-slate-500 dark:text-slate-400 uppercase tracking-wider">{tx.date}</p>
                </div>
              </div>
              <div className="text-right">
                <p className={`font-bold text-sm ${tx.type === 'income' ? 'text-primary' : 'text-slate-900 dark:text-white'}`}>
                  {tx.amount > 0 ? '+' : '-'}{tx.currency === 'USD' ? '$' : tx.currency === 'EUR' ? '€' : tx.currency === 'GBP' ? '£' : '₦'}
                  {Math.abs(tx.amount).toLocaleString(undefined, { minimumFractionDigits: 2 })}
                </p>
                <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">{tx.currency} Wallet</p>
              </div>
            </div>
          ))}
        </div>
      </section>

      {/* Receive Funds Modal */}
      {showReceiveModal && selectedWallet && (
        <div className="fixed inset-0 z-[100] flex items-end justify-center px-4 pb-4">
          <div className="absolute inset-0 bg-background-dark/80 backdrop-blur-sm animate-in fade-in" onClick={() => setShowReceiveModal(false)}></div>
          <div className="bg-white dark:bg-surface-dark w-full max-w-md rounded-[40px] p-8 relative z-10 animate-in slide-in-from-bottom-20 duration-500">
            <div className="flex justify-between items-center mb-6">
              <div className="flex items-center gap-3">
                <img src={selectedWallet.flagUrl} alt="" className="w-8 h-6 rounded shadow-sm" />
                <h3 className="text-lg font-bold">Receive {selectedWallet.currency}</h3>
              </div>
              <button onClick={() => setShowReceiveModal(false)} className="w-10 h-10 flex items-center justify-center bg-slate-100 dark:bg-white/5 rounded-full">
                <span className="material-icons-round text-slate-400">close</span>
              </button>
            </div>

            {selectedWallet.bankAccount ? (
              <div className="space-y-6">
