                <div className="space-y-4">
                  <div className="p-4 rounded-[20px] bg-white dark:bg-surface-dark border border-slate-200 dark:border-white/5">
                    <p className="text-[9px] uppercase font-bold text-slate-500 mb-0.5">Beneficiary Name</p>
                    <p className="font-bold">{selectedWallet.bankAccount.accountName}</p>
                  </div>

                  {selectedWallet.bankAccount.details.map((detail, idx) => (
                    <div key={idx} className="p-4 rounded-[20px] bg-white dark:bg-surface-dark border border-slate-200 dark:border-white/5 flex justify-between items-center">
                      <div>
                        <p className="text-[9px] uppercase font-bold text-slate-500 mb-0.5">{detail.label}</p>
                        <p className="font-mono font-bold">{detail.value}</p>
                      </div>
                      {detail.isCopyable && (
                        <button 
                          onClick={() => copyToClipboard(detail.value, detail.label)}
                          className={`w-10 h-10 rounded-full flex items-center justify-center transition-all ${copyFeedback === detail.label ? 'bg-green-500 text-white' : 'bg-primary/10 text-primary hover:bg-primary/20'}`}
                        >
                          <span className="material-icons-round text-lg">{copyFeedback === detail.label ? 'check' : 'content_copy'}</span>
                        </button>
                      )}
