};

export default Home;

export enum View {
  HOME = 'home',
  WALLETS = 'wallets',
  SEND = 'send',
  CARDS = 'cards',
  ENGINE = 'engine',
  CONVERT = 'convert',
  RECEIVE = 'receive'
}

export interface BankDetail {
  label: string;
  value: string;
  isCopyable?: boolean;
}

export interface BankAccount {
  institution: string;
  accountName: string;
  details: BankDetail[];
}

export interface Transaction {
  id: string;
  name: string;
  date: string;
  amount: number;
  currency: 'USD' | 'EUR' | 'GBP' | 'NGN';
  type: 'expense' | 'income';
  icon: string;
}

export interface Wallet {
  currency: string;
  label: string;
  balance: number;
  symbol: string;
  flagUrl: string;
  color: string;
  bankAccount?: BankAccount;
}

import React, { useState } from 'react';
import { View, Wallet } from './types';
import Home from './components/Home';
import Convert from './components/Convert';
import Send from './components/Send';
import Receive from './components/Receive';
import Navigation from './components/Navigation';
import { INITIAL_WALLETS } from './constants';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.HOME);
  const [wallets, setWallets] = useState<Wallet[]>(INITIAL_WALLETS);
  const [activeWallet, setActiveWallet] = useState<Wallet | null>(null);

  const handleAddWallet = (newWallet: Wallet) => {
    setWallets(prev => [...prev, newWallet]);
  };

  const handleNavigateToReceive = (wallet: Wallet) => {
    setActiveWallet(wallet);
    setCurrentView(View.RECEIVE);
  };

  const renderContent = () => {
    switch (currentView) {
      case View.HOME:
        return (
          <Home 
            wallets={wallets}
            onAddWallet={handleAddWallet}
            onNavigateToConvert={() => setCurrentView(View.CONVERT)} 
            onNavigateToSend={() => setCurrentView(View.SEND)}
            onNavigateToReceive={handleNavigateToReceive}
          />
        );
      case View.CONVERT:
        return <Convert onBack={() => setCurrentView(View.HOME)} />;
      case View.SEND:
        return (
          <Send 
            wallets={wallets} 
            onBack={() => setCurrentView(View.HOME)} 
          />
        );
      case View.RECEIVE:
        return (
          <Receive 
            wallet={activeWallet || wallets[0]} 
            onBack={() => setCurrentView(View.HOME)} 
          />
        );
      case View.WALLETS:
      case View.CARDS:
      case View.ENGINE:
        return (
          <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center">
             <span className="material-icons-round text-6xl text-primary mb-4 animate-pulse">
                {currentView === View.WALLETS ? 'account_balance_wallet' : 
                 currentView === View.CARDS ? 'credit_card' : 'bolt'}
             </span>
             <h2 className="text-xl font-bold mb-2 uppercase tracking-widest">{currentView} View</h2>
             <p className="text-slate-500">This section is currently under development.</p>
             <button 
                onClick={() => setCurrentView(View.HOME)}
                className="mt-6 px-6 py-2 bg-primary text-background-dark font-bold rounded-xl active:scale-95 transition-transform"
             >
                Back Home
             </button>
          </div>
        );
      default:
        return (
          <Home 
            wallets={wallets}
            onAddWallet={handleAddWallet}
            onNavigateToConvert={() => setCurrentView(View.CONVERT)} 
            onNavigateToSend={() => setCurrentView(View.SEND)}
            onNavigateToReceive={handleNavigateToReceive}
          />
        );
    }
  };

  const showNav = ![View.CONVERT, View.SEND, View.RECEIVE].includes(currentView);

  return (
    <div className="flex justify-center min-h-screen w-full relative overflow-hidden transition-colors duration-500">
      <div className="absolute inset-0 pattern-overlay pointer-events-none"></div>

      <div className="w-full max-w-md flex flex-col relative z-10 bg-background-light dark:bg-background-dark min-h-screen">
        <div className="flex-1">
          {renderContent()}
        </div>

        {showNav && (
          <Navigation currentView={currentView} onNavigate={setCurrentView} />
        )}
      </div>

      <button 
        className="fixed bottom-24 right-4 md:right-auto md:left-[calc(50%+200px)] bg-white dark:bg-surface-dark p-3 rounded-full shadow-lg border border-slate-200 dark:border-white/10 z-[60] active:scale-95 transition-all"
        onClick={() => document.documentElement.classList.toggle('dark')}
      >
        <span className="material-icons-round dark:text-white block">
          {typeof document !== 'undefined' && document.documentElement.classList.contains('dark') ? 'light_mode' : 'dark_mode'}
        </span>
      </button>
    </div>
  );
};

