import React, { useState } from 'react';
import { View, Wallet, Transaction } from './types';
import Home from './components/Home';
import Convert from './components/Convert';
import Send from './components/Send';
import Receive from './components/Receive';
import TransactionDetails from './components/TransactionDetails';
import Wallets from './components/Wallets';
import Navigation from './components/Navigation';
import { INITIAL_WALLETS } from './constants';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.HOME);
  const [wallets, setWallets] = useState<Wallet[]>(INITIAL_WALLETS);
  const [activeWallet, setActiveWallet] = useState<Wallet | null>(null);
  const [activeTransaction, setActiveTransaction] = useState<Transaction | null>(null);

  const handleAddWallet = (newWallet: Wallet) => {
    setWallets(prev => [...prev, newWallet]);
  };

  const handleNavigateToReceive = (wallet: Wallet) => {
    setActiveWallet(wallet);
    setCurrentView(View.RECEIVE);
  };

  const handleNavigateToSend = (wallet?: Wallet) => {
    if (wallet) {
      setActiveWallet(wallet);
    } else {
      setActiveWallet(null);
    }
    setCurrentView(View.SEND);
  };

  const handleNavigateToTransaction = (tx: Transaction) => {
    setActiveTransaction(tx);
    setCurrentView(View.TRANSACTION_DETAILS);
  };

  const renderContent = () => {
    switch (currentView) {
      case View.HOME:
        return (
          <Home 
            wallets={wallets}
            onAddWallet={handleAddWallet}
            onNavigateToConvert={() => setCurrentView(View.CONVERT)} 
            onNavigateToSend={handleNavigateToSend}
            onNavigateToReceive={handleNavigateToReceive}
            onNavigateToTransaction={handleNavigateToTransaction}
          />
        );
      case View.CONVERT:
        return <Convert onBack={() => setCurrentView(View.HOME)} />;
      case View.SEND:
        return (
          <Send 
            wallets={wallets} 
            onBack={() => { setActiveWallet(null); setCurrentView(View.HOME); }} 
            initialWallet={activeWallet || undefined}
          />
        );
      case View.RECEIVE:
        return (
          <Receive 
            wallet={activeWallet || wallets[0]} 
            onBack={() => { setActiveWallet(null); setCurrentView(View.HOME); }} 
          />
        );
      case View.TRANSACTION_DETAILS:
        return (
          <TransactionDetails 
            transaction={activeTransaction} 
            onBack={() => setCurrentView(View.HOME)} 
          />
        );
      case View.WALLETS:
        return (
          <Wallets 
            wallets={wallets}
            onAddWallet={handleAddWallet}
            onNavigateToReceive={handleNavigateToReceive}
            onNavigateToSend={handleNavigateToSend}
          />
        );
      case View.CARDS:
      case View.ENGINE:
        return (
          <div className="flex flex-col items-center justify-center min-h-screen p-6 text-center">
             <span className="material-icons-round text-6xl text-primary mb-4 animate-pulse">
                {currentView === View.CARDS ? 'credit_card' : 'bolt'}
             </span>
             <h2 className="text-xl font-bold mb-2 uppercase tracking-widest">{currentView} View</h2>
             <p className="text-slate-500">This section is currently under development.</p>
             <button 
                onClick={() => setCurrentView(View.HOME)}
                className="mt-6 px-6 py-2 bg-primary text-background-dark font-bold rounded-xl active:scale-95 transition-transform"
             >
                Back Home
             </button>
          </div>
        );
      default:
        return (
          <Home 
            wallets={wallets}
            onAddWallet={handleAddWallet}
            onNavigateToConvert={() => setCurrentView(View.CONVERT)} 
            onNavigateToSend={handleNavigateToSend}
            onNavigateToReceive={handleNavigateToReceive}
            onNavigateToTransaction={handleNavigateToTransaction}
          />
        );
    }
  };

  const showNav = ![View.CONVERT, View.SEND, View.RECEIVE, View.TRANSACTION_DETAILS].includes(currentView);

  return (
    <div className="flex justify-center min-h-screen w-full relative overflow-hidden transition-colors duration-500">
      <div className="absolute inset-0 pattern-overlay pointer-events-none"></div>

      <div className="w-full max-w-md flex flex-col relative z-10 bg-background-light dark:bg-background-dark min-h-screen">
        <div className="flex-1">
          {renderContent()}
        </div>

        {showNav && (
          <Navigation currentView={currentView} onNavigate={setCurrentView} />
        )}
      </div>

      <button 
        className="fixed bottom-24 right-4 md:right-auto md:left-[calc(50%+200px)] bg-white dark:bg-surface-dark p-3 rounded-full shadow-lg border border-slate-200 dark:border-white/10 z-[60] active:scale-95 transition-all"
        onClick={() => document.documentElement.classList.toggle('dark')}
      >
        <span className="material-icons-round dark:text-white block">
          {typeof document !== 'undefined' && document.documentElement.classList.contains('dark') ? 'light_mode' : 'dark_mode'}
        </span>
      </button>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Wallet } from '../types';

interface SendProps {
  wallets: Wallet[];
  onBack: () => void;
  initialWallet?: Wallet;
}

interface Beneficiary {
  name: string;
  bankName: string;
  accountNumber: string;
  identifier?: string; 
}

const Send: React.FC<SendProps> = ({ wallets, onBack, initialWallet }) => {
  const [step, setStep] = useState<'amount' | 'beneficiary' | 'pin' | 'processing' | 'success'>('amount');
  const [selectedWallet, setSelectedWallet] = useState<Wallet>(initialWallet || wallets[0]);
  const [showWalletSelector, setShowWalletSelector] = useState(false);

  const [inputValue, setInputValue] = useState('0');
  const [numericValue, setNumericValue] = useState(0);

  const [beneficiary, setBeneficiary] = useState<Beneficiary>({
    name: '',
    bankName: '',
    accountNumber: '',
  });

  const [pin, setPin] = useState<string>('');
  const [transactionId, setTransactionId] = useState('');

  const handleKeyPress = (key: string) => {
    let current = inputValue.replace(/,/g, '');
    if (key === 'backspace') {
      current = current.slice(0, -1);
    } else if (key === '.') {
      if (!current.includes('.')) current += '.';
    } else {
      if (current === '0') current = key;
      else current += key;
    }

    if (current === '') current = '0';

    const num = parseFloat(current);
    if (!isNaN(num)) {
      setNumericValue(num);
      const parts = current.split('.');
      parts[0] = Math.floor(parseFloat(parts[0])).toLocaleString();
      setInputValue(parts.join('.'));
    } else if (current === '0' || current === '') {
      setNumericValue(0);
      setInputValue('0');
    }
  };

  const handlePinPress = (digit: string) => {
    if (pin.length < 4) {
      setPin(prev => prev + digit);
    }
  };

  const handlePinBackspace = () => {
    setPin(prev => prev.slice(0, -1));
  };

  useEffect(() => {
    if (pin.length === 4) {
      // Small delay for visual feedback of the last digit
      const timer = setTimeout(() => {
        setStep('processing');
        setTransactionId('TXN-' + Math.random().toString(36).substring(2, 10).toUpperCase());

        setTimeout(() => {
          setStep('success');
        }, 2500);
      }, 300);
      return () => clearTimeout(timer);
    }
  }, [pin]);

  const handleConfirmBeneficiary = (e: React.FormEvent) => {
    e.preventDefault();
    if (!beneficiary.name || !beneficiary.accountNumber) return;
    setStep('pin');
  };

  if (step === 'processing') {
    return (
      <div className="flex flex-col items-center justify-center min-h-screen bg-background-dark p-6">
        <div className="relative w-32 h-32 mb-8">
            <div className="absolute inset-0 rounded-full border-4 border-primary/20 border-t-primary animate-spin"></div>
            <div className="absolute inset-4 rounded-full border-4 border-white/5 border-b-primary/40 animate-spin-slow"></div>
            <div className="absolute inset-0 flex items-center justify-center">
                <span className="material-icons-round text-primary text-4xl">send</span>
            </div>
        </div>
        <h2 className="text-xl font-bold mb-2 animate-pulse uppercase tracking-[0.2em]">Sending Funds</h2>
        <p className="text-slate-400 text-sm max-w-[200px] text-center">Your request is being processed by the network...</p>
      </div>
    );
  }

  if (step === 'pin') {
    return (
      <div className="flex flex-col min-h-screen bg-background-light dark:bg-background-dark p-6 z-[120] animate-in slide-in-from-bottom-20 duration-500">
        <header className="py-4 mb-10 text-center">
          <div className="w-16 h-16 bg-primary/10 rounded-2xl flex items-center justify-center mx-auto mb-4 border border-primary/20">
             <span className="material-icons-round text-primary text-3xl">lock</span>
          </div>
          <h2 className="text-2xl font-black mb-1">Enter Security PIN</h2>
          <p className="text-slate-500 text-xs uppercase tracking-widest font-bold">Verify your identity to proceed</p>
        </header>

        <main className="flex-1 flex flex-col items-center">
          <div className="flex gap-4 mb-16">
            {[0, 1, 2, 3].map((i) => (
              <div 
                key={i}
                className={`w-4 h-4 rounded-full border-2 transition-all duration-300 ${
                  pin.length > i 
                    ? 'bg-primary border-primary scale-125 shadow-[0_0_15px_rgba(183,204,22,0.5)]' 
                    : 'border-slate-300 dark:border-white/20'
                }`}
              />
            ))}
          </div>

          <div className="w-full max-w-xs grid grid-cols-3 gap-6">
            {['1', '2', '3', '4', '5', '6', '7', '8', '9'].map((digit) => (
              <button
                key={digit}
                onClick={() => handlePinPress(digit)}
                className="w-full aspect-square rounded-2xl bg-white dark:bg-surface-dark border border-slate-200 dark:border-white/5 text-2xl font-black active:scale-90 active:bg-primary active:text-background-dark transition-all flex items-center justify-center"
              >
                {digit}
              </button>
            ))}
            <div />
            <button
              onClick={() => handlePinPress('0')}
              className="w-full aspect-square rounded-2xl bg-white dark:bg-surface-dark border border-slate-200 dark:border-white/5 text-2xl font-black active:scale-90 active:bg-primary active:text-background-dark transition-all flex items-center justify-center"
            >
              0
            </button>
            <button
              onClick={handlePinBackspace}
              className="w-full aspect-square rounded-2xl flex items-center justify-center active:scale-90 text-slate-400"
            >
              <span className="material-icons-round text-3xl">backspace</span>
            </button>
          </div>

          <button className="mt-12 text-primary font-bold text-xs uppercase tracking-widest hover:underline">
            Forgot Security PIN?
          </button>
        </main>

        <footer className="py-8">
           <button 
             onClick={() => { setStep('beneficiary'); setPin(''); }}
             className="w-full py-4 text-slate-400 font-bold uppercase tracking-widest text-xs"
           >
             Cancel Transaction
           </button>
        </footer>
      </div>
    );
  }

  if (step === 'success') {
    return (
      <div className="flex flex-col min-h-screen bg-background-light dark:bg-background-dark p-6 animate-in fade-in duration-700">
        <div className="flex-1 flex flex-col items-center pt-8">
          <div className="w-20 h-20 rounded-full bg-primary flex items-center justify-center shadow-2xl shadow-primary/40 mb-6 animate-in zoom-in duration-500 delay-200">
            <span className="material-icons-round text-background-dark text-4xl">check</span>
