            <div className={`w-12 h-12 rounded-2xl flex items-center justify-center transition-colors ${isFrozen ? 'bg-primary/20 text-primary' : 'bg-slate-100 dark:bg-white/5 text-slate-400'}`}>
              <span className="material-icons-round">{isFrozen ? 'ac_unit' : 'bolt'}</span>
            </div>
            <div>
              <p className="font-bold">Freeze Card</p>
              <p className="text-[10px] text-slate-500 uppercase font-bold tracking-wider">Instantly disable spending</p>
            </div>
          </div>
          <button 
            onClick={() => initiateAction('toggleFreeze')}
            className={`relative w-14 h-8 rounded-full transition-colors duration-300 ${isFrozen ? 'bg-primary' : 'bg-slate-200 dark:bg-white/10'}`}
          >
            <div className={`absolute top-1 w-6 h-6 bg-white dark:bg-slate-900 rounded-full transition-all duration-300 shadow-md ${isFrozen ? 'left-7' : 'left-1'}`}></div>
